#include <stdio.h>
#include <stdlib.h>

#define MAX_NODES 100002

typedef struct Node {
    int vertex;
    struct Node* next;
} Node;

Node* adj[MAX_NODES];
int* nodes_at_level_k;
int nodes_count;

void add_edge(int u, int v) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->vertex = v;
    newNode->next = adj[u];
    adj[u] = newNode;
}

void dfs(int u, int par, int k, int level) {
    if (level == k) {
        nodes_at_level_k[nodes_count++] = u;
    }
    Node* current = adj[u];
    while (current != NULL) {
        int v = current->vertex;
        if (v != par) {
            dfs(v, u, k, level + 1);
        }
        current = current->next;
    }
}

int cmpfunc(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int n, k;
    scanf("%d %d", &n, &k);

    // Input validation
    if (k < 0 || k >= n) {
        return 1; // Invalid input, exit the program
    }

    // Initialize adjacency list
    for (int i = 0; i <= n; i++) {
        adj[i] = NULL;
    }

    // Initialize nodes_at_level_k
    nodes_at_level_k = (int*)malloc(n * sizeof(int));
    nodes_count = 0;

    // Read edges and build adjacency list
    for (int i = 1; i < n; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        add_edge(u, v);
        add_edge(v, u);
    }

    // Start DFS from node 1
    dfs(1, 0, k, 0);

    // Sort the nodes at level k
    qsort(nodes_at_level_k, nodes_count, sizeof(int), cmpfunc);

    // Print the nodes at level k
    for (int i = 0; i < nodes_count; i++) {
        printf("%d ", nodes_at_level_k[i]);
    }
    printf("\n");

    // Free the allocated memory
    free(nodes_at_level_k);
    for (int i = 0; i <= n; i++) {
        Node* current = adj[i];
        while (current != NULL) {
            Node* temp = current;
            current = current->next;
            free(temp);
        }
    }

    return 0;
}

