import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Scanner;

class Codechef {

    static List<Integer>[] adj = new ArrayList[100001];
    static List<Integer> nodesAtLevelK = new ArrayList<>();

    public static void dfs(int u, int par, int k, int level) {
        if (level == k) {
            nodesAtLevelK.add(u);
        }
        for (int v : adj[u]) {
            if (v != par) {
                dfs(v, u, k, level + 1);
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int k = sc.nextInt();

        if (k < 0 || k >= n) {
            System.err.println("Invalid value for k: " + k);
            return;
        }

        // Initialize adjacency list
        for (int i = 0; i < adj.length; i++) {
            adj[i] = new ArrayList<>();
        }

        for (int i = 1; i < n; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            if (u >= adj.length || v >= adj.length) {
                System.err.println("Node index out of bounds: u = " + u + ", v = " + v);
                return;
            }
            adj[u].add(v);
            adj[v].add(u);
        }

        dfs(1, 0, k, 0);
        Collections.sort(nodesAtLevelK);

        for (int node : nodesAtLevelK) {
            System.out.print(node + " ");
        }
        System.out.println();
    }
}

