const readline = require('readline');

const adj = [];
const nodesAtLevelK = [];

function dfs(u, par, k, level) {
    if (level === k) {
        nodesAtLevelK.push(u);
    }
    for (let v of adj[u]) {
        if (v === par) continue;
        dfs(v, u, k, level + 1);
    }
}

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let n = 0, k = 0;
    let edgeCount = 0;

    rl.on('line', (line) => {
        if (n === 0) {
            [n, k] = line.trim().split(' ').map(Number);
            for (let i = 0; i <= n; i++) {
                adj.push([]);
            }
        } else {
            const [u, v] = line.trim().split(' ').map(Number);
            adj[u].push(v);
            adj[v].push(u);
            edgeCount++;
            if (edgeCount === n - 1) {
                rl.close();
            }
        }
    });

    rl.on('close', () => {
        dfs(1, 0, k, 0);
        nodesAtLevelK.sort((a, b) => a - b);
        console.log(nodesAtLevelK.join(' '));
        process.exit(0);
    });
}

// Run the main function
main();
